#include "mlx90614.h"
#include <Wire.h>
#include <Adafruit_MLX90614.h>
static Adafruit_MLX90614 mlx;
static float _obj=0,_amb=0;
static unsigned long _last=0;
void mlx90614_setup(){Wire.begin();if(!mlx.begin()){Serial.println("[mlx90614] Fail!");return;}Serial.println("[mlx90614] OK");}
void mlx90614_loop(){if(millis()-_last<500)return;_last=millis();_obj=mlx.readObjectTempC();_amb=mlx.readAmbientTempC();}
float mlx90614_get_object_temp(){return _obj;}
float mlx90614_get_ambient_temp(){return _amb;}
